mapper.select:
SELECT t.* FROM ( SELECT a.user_id userId,a.user_b_id userBId,a.clean_type cleanType, CASE clean_type WHEN 1 THEN '普洗' WHEN 2 THEN '精洗' WHEN 3 THEN '自动' WHEN 4 THEN '夜洗' WHEN 5 THEN '免费' ELSE '洗车' END AS cleanName, CASE car_type WHEN 1 THEN '小型轿车' WHEN 2 THEN '小型越野' WHEN 3 THEN '大型越野' WHEN 4 THEN '商务车' ELSE '小型轿车' END AS carName, clean_indent_number cleanIndentNumber,amount*0.9 amount,indent_state indentState,b.url imgUrl,is_evaluation isEvaluation,a.create_time createTime,a.resource,CONCAT('') rescueName, CONCAT('') currentPosition FROM app_clean_indet as a LEFT JOIN app_merchants_info_banner as b on a.user_b_id = b.user_b_id WHERE a.user_b_id = #{id} AND a.resource = 1 AND b.`index`= 1 AND a.indent_state <> 1
AND (a.indent_state = #{type} or a.indent_state = 6)
AND a.indent_state = #{type}
union all SELECT a.user_id userId,a.user_b_id userBId,a.clean_type cleanType,b.beauty_name cleanName, CASE a.car_type WHEN 1 THEN '小型轿车' WHEN 2 THEN '小型越野' WHEN 3 THEN '大型越野' WHEN 4 THEN '商务车' ELSE '小型轿车' END AS carName,a.clean_indent_number cleanIndentNumber,amount*0.9 amount,a.indent_state indentState,c.url imgUrl,is_evaluation isEvaluation,a.create_time createTime,a.resource,CONCAT('') rescueName, CONCAT('') currentPosition FROM app_clean_indet as a LEFT JOIN app_beauty_type as b ON a.clean_type = b.beauty_type LEFT JOIN app_merchants_info_banner as c on a.user_b_id = c.user_b_id WHERE a.user_b_id = #{id} AND resource = 2 AND c.`index` = 1 AND a.indent_state <> 1
AND (a.indent_state = #{type} or a.indent_state = 6)
AND a.indent_state = #{type}
union all SELECT a.user_id userId,a.user_b_id userBId,a.type cleanType, CASE a.type WHEN 1 THEN '搭电' WHEN 2 THEN '拖车' WHEN 3 THEN '送胎' ELSE '救援' END AS cleanName,CONCAT('不限车型') carName,a.rescue_number cleanIndentNumber,price*0.8 amount,a.state indentState,b.url imgUrl, CONCAT(1) isEvaluation,a.create_time createTime,CONCAT(3) resource,rescue_name rescueName, current_position currentPosition FROM app_rescue_indent as a LEFT JOIN app_rescue_img as b on a.type = b.type WHERE a.user_b_id = #{id} AND a.state <> 1
AND a.state = #{type}
union all SELECT a.user_id userId,a.user_b_id userBId,CONCAT('')cleanType, CONCAT('喷漆')cleanName,brand_type carName,a.spray_paint_number cleanIndentNumber, a.price*0.8 amount,a.state indentState,b.url url,a.is_evaluation isEvaluation, a.create_time createTime,CONCAT(4) resource,CONCAT('') rescueName,pick_address currentPosition FROM app_spray_paint_indent as a LEFT JOIN app_spray_paint_img as b ON a.id = b.spray_paint_id WHERE a.user_b_id = #{id} AND b.`index` = 1
AND a.state = 2
AND (a.state = 3 or a.state = 6)
AND a.state = 4
union all SELECT a.user_id userId,a.user_b_id userBId,CONCAT('')cleanType, CASE a.year_check_type WHEN 1 THEN '免检代办' WHEN 2 THEN '线上年检' ELSE '年检' END AS cleanName,CONCAT('不限车型') carName,a.year_check_number cleanIndentNumber,a.price*0.8 amount,a.state indentState,b.url imgUrl, CONCAT(1) isEvaluation,a.create_time createTime,CONCAT(5) resource,CONCAT('') rescueName,pick_address currentPosition FROM app_year_check_indent as a LEFT JOIN app_merchants_info_banner as b ON a.user_b_id = b.user_b_id WHERE b.`index` = 1 AND a.user_b_id = #{id} AND a.state <> 1
AND a.state = #{type}
)t
order by createTime DESC LIMIT #{pagesize},20

SELECT t.* FROM ( SELECT a.user_id userId,a.user_b_id userBId,a.clean_type cleanType, CASE clean_type WHEN 1 THEN '普洗' WHEN 2 THEN '精洗' WHEN 3 THEN '自动' WHEN 4 THEN '夜洗' WHEN 5 THEN '免费' ELSE '洗车' END AS cleanName, CASE car_type WHEN 1 THEN '小型轿车' WHEN 2 THEN '小型越野' WHEN 3 THEN '大型越野' WHEN 4 THEN '商务车' ELSE '小型轿车' END AS carName, clean_indent_number cleanIndentNumber,amount*0.9 amount,indent_state indentState,b.url imgUrl,is_evaluation isEvaluation,a.create_time createTime,a.resource,CONCAT('') rescueName, CONCAT('') currentPosition FROM app_clean_indet as a LEFT JOIN app_merchants_info_banner as b on a.user_b_id = b.user_b_id WHERE a.user_b_id = #{id} AND a.resource = 1 AND b.`index`= 1 AND a.indent_state <> 1
AND (a.indent_state = #{type} or a.indent_state = 6)
AND a.indent_state = #{type}
union all SELECT a.user_id userId,a.user_b_id userBId,a.clean_type cleanType,b.beauty_name cleanName, CASE a.car_type WHEN 1 THEN '小型轿车' WHEN 2 THEN '小型越野' WHEN 3 THEN '大型越野' WHEN 4 THEN '商务车' ELSE '小型轿车' END AS carName,a.clean_indent_number cleanIndentNumber,amount*0.9 amount,a.indent_state indentState,c.url imgUrl,is_evaluation isEvaluation,a.create_time createTime,a.resource,CONCAT('') rescueName, CONCAT('') currentPosition FROM app_clean_indet as a LEFT JOIN app_beauty_type as b ON a.clean_type = b.beauty_type LEFT JOIN app_merchants_info_banner as c on a.user_b_id = c.user_b_id WHERE a.user_b_id = #{id} AND resource = 2 AND c.`index` = 1 AND a.indent_state <> 1
AND (a.indent_state = #{type} or a.indent_state = 6)
AND a.indent_state = #{type}
)t
order by createTime DESC LIMIT #{pagesize},20
